-- Pattern: face-comparison
INSERT INTO patterns (id, name, status, confidence, protocol_md, trigger_keywords, trigger_error_signatures, times_used, times_correct, false_positives, false_positive_log, sprint_validated, created_at)
VALUES (
  'face-comparison',
  'Face / Selfie Comparison Failures',
  'active',
  'HIGH',
  E'# Pattern: Face / Selfie Comparison Failures\n\n**ID**: face-comparison\n\n---\n\n## TRIGGER\n\nActivate this pattern when ALL of the following are true:\n\n- Test name or story contains any of: `compare faces`, `selfie`, `IPCF`, `liveness`, `face match`\n- Error message contains any of: `Selfie Face Match`, `verifyPhotoHasSelfieFaceMatch`, `Expected: a string containing \"Yes\"`, `Expected: a string containing \"No\"`\n- Test involves photo upload steps for two or more photos\n\n**Do NOT activate** for general photo upload failures that do not involve face comparison assertions.\n\n---\n\n## PROTOCOL\n\nExecute these steps in strict order. Do not skip to git correlation until Step 2 is resolved.\n\n### Step 1 — Validate Test Inputs FIRST (before any code or git investigation)\n\nThis is the most important step. Do not touch any repo until inputs are validated.\n\n```bash\n# 1a. Identify which PhotoType values are used in the test feature file\ngrep -n \"PhotoType\\|APPROVED\\|PUBLIC\\|PRIVATE\\|SELFIE\" $QA_REPO/src/test/resources/features/**/*<test_name>*.feature\n\n# 1b. Resolve each PhotoType to its actual file path using the mapping table below\n# 1c. Compute MD5 hash of each resolved file\nmd5 $QA_REPO/src/test/resources/testdata/profile-photos/<resolved_path_1>\nmd5 $QA_REPO/src/test/resources/testdata/profile-photos/<resolved_path_2>\n```\n\n**PhotoType Resolution Map:**\n| PhotoType | Resolved Path |\n|-----------|---------------|\n| `PUBLIC` | `public/<userType>-1.jpg` (userType from test DB) |\n| `PRIVATE` | `private/<userType>-1.jpg` |\n| `APPROVED_MALE` | `public/misc-photos/approved_male.jpg` |\n| `APPROVED_SELFIE` | `public/misc-photos/approved_selfie.jpg` |\n| `APPROVED_FEMALE` | `public/misc-photos/approved_female.jpg` |\n| Other | `public/misc-photos/<type_lowercase>.jpg` |\n\n### Step 2 — Decision Gate: Are the photos identical?\n\n**IF hashes match (identical photos):**\n→ This is a QA Automation issue. Photos are duplicates. Proceed to Step 3.\n\n**IF hashes differ (different photos):**\n→ Input is correct. Photos are genuinely different. Skip to Step 5 (BE investigation).\n\n### Step 3 — Trace the Duplicate (QA path only)\n\nFind when and why the files became identical:\n\n```bash\ngit -C $QA_REPO log --oneline --follow -- <path_to_photo_1>\ngit -C $QA_REPO log --oneline --follow -- <path_to_photo_2>\ngit -C $QA_REPO log --oneline --since=\"14 days ago\" -- <feature_file_path>\ngit -C $QA_REPO log --oneline --since=\"14 days ago\" -- <step_definition_path>\n```\n\n### Step 4 — Chain of Causation (QA path only)\n\nIdentify and report:\n- **Root Cause commit**: When did the file get replaced/duplicated? (may be months old)\n- **Sprint Trigger commit**: What recent change caused this old duplicate to now produce a failure?\n- **Why now**: Was this test recently added to the run suite? Was a PhotoType reference changed?\n\n**Termination**: Classify as `QA Automation` | `HIGH` confidence. Recommend fix: replace duplicate image with genuinely distinct file.\n\n### Step 5 — BE Investigation (Different photos path only)\n\nPhotos are genuinely different but face comparison is still failing:\n\n```bash\ngit -C $BE_REPO log --oneline --since=\"14 days ago\" -- <compare_faces_service_path>\ngit -C $BE_REPO log --oneline --since=\"14 days ago\" -- <api_routes_path>\ngit -C $BE_REPO log --oneline --since=\"14 days ago\" -- <config_path>\n```\n\n**Termination**: Classify as `BE Code` with evidence from commits. If no recent BE changes found, classify as `Flaky/Inconclusive` | `LOW` confidence.\n\n---\n\n## TERMINATION CONDITIONS\n\n| Outcome | Classification | Confidence |\n|---------|---------------|------------|\n| Duplicate photos found, root cause commit identified | QA Automation | HIGH |\n| Duplicate photos found, no clear commit (old rename) | QA Automation | MEDIUM |\n| Different photos, recent BE commit found | BE Code | HIGH |\n| Different photos, no recent changes anywhere | Flaky/Inconclusive | LOW |',
  ARRAY['compare faces', 'selfie', 'face match', 'Selfie Face Match', 'liveness'],
  ARRAY['Selfie Face Match: No', 'Selfie Face Match: Yes', 'verifyPhotoHasSelfieFaceMatch'],
  2, 1, 1,
  '[{"date":"2026-03-13","test":"ID Verification Underage Improvements","reason":"Generic error signature matched without keyword hit. Fixed by removing Expected: a string containing and enforcing keyword_required rule."}]'::jsonb,
  '2026-03-06',
  '2026-03-06'
) ON CONFLICT (id) DO NOTHING;

-- Pattern: dragyn-false-positive
INSERT INTO patterns (id, name, status, confidence, protocol_md, trigger_keywords, trigger_error_signatures, times_used, times_correct, false_positives, false_positive_log, sprint_validated, created_at)
VALUES (
  'dragyn-false-positive',
  'Dragyn ML False Positive / Wrong Reason',
  'active',
  'HIGH',
  E'# Pattern: Dragyn ML False Positive\n\n**ID**: dragyn-false-positive\n\n---\n\n## TRIGGER\n\nActivate this pattern when ALL of the following are true:\n\n- Test name or story contains any of: `Dragyn`, `photo moderation`, `dragyn photo`, `dragyn recommendation`\n- Error message contains: `Dragyn history table has reason for`\n- Test involves a photo upload with a known content_type\n\n**Do NOT activate** for Dragyn failures where the error is element not found, timeout, or login failures.\n\n---\n\n## PROTOCOL\n\n### Step 1 — Get the actual Dragyn reason from Serenity recorded data\n\nDo NOT guess from the error message alone.\n\n```python\nimport json, sys\nwith open(\"<serenity_json_file>\") as f:\n    data = json.load(sys.stdin)\ndef find(steps):\n    for s in steps:\n        for e in s.get(''reportData'', []):\n            if ''Dragyn reason'' in e.get(''title'', ''''):\n                print(e[''title''], ''->'', e[''contents''])\n        find(s.get(''children'', []))\nfind(data.get(''testSteps'', []))\n```\n\nRecord: **actual_reason** = whatever getDragynReason().getText() returned.\n\n### Step 2 — Confirm whether QA override is intentionally absent\n\n```bash\ngit -C $QA_REPO log --oneline --since=\"14 days ago\" -- <upload_step_definition_path>\ngit -C $QA_REPO show <sha> -- <upload_step_definition_path> | grep -i \"qa_override\\|x-qa-override\"\n```\n\n| Finding | Meaning | Next Step |\n|---------|---------|----------|\n| Override **recently removed** | Regression | Step 3 (QA path) |\n| Override **never present** | Intentional E2E | Step 4 (Dragyn path) |\n\n### Step 3 — QA Regression Path\n\n```bash\ngit -C $QA_REPO log --oneline -S \"qa_override\\|x-qa-override\" -- <step_definition_path>\ngit -C $QA_REPO log --oneline --since=\"14 days ago\" -- <feature_file_path>\n```\n\n**Termination**: Classify as `QA Automation` | `HIGH` confidence.\n\n### Step 4 — Dragyn False Positive Path\n\n```bash\ngit -C $QA_REPO log --oneline --since=\"14 days ago\" -- <image_file_path>\ngit -C $BE_REPO log --oneline --since=\"14 days ago\" -- app/Repositories/Dragyn/\ngit -C $BE_REPO log --oneline --since=\"14 days ago\" -- app/Http/Controllers/Api/Mock/DragynController.php\n```\n\n**If image changed recently** → QA Automation\n**If no recent changes** → External Service — Dragyn Misclassification\n\n---\n\n## TERMINATION CONDITIONS\n\n| Outcome | Classification | Confidence |\n|---------|---------------|------------|\n| QA override recently removed | QA Automation | HIGH |\n| Override never present + image changed | QA Automation | MEDIUM |\n| Override never present + no changes + reason mismatch | External Service — Dragyn Misclassification | HIGH |\n| Override never present + actual reason matches expected | No failure (transient) | N/A |',
  ARRAY['Dragyn', 'dragyn', 'photo moderation', 'dragyn recommendation', 'dragyn history'],
  ARRAY['Dragyn history table has reason for', 'adminChecksDragynReasonDragynHistoryTable'],
  1, 1, 0,
  '[]'::jsonb,
  '2026-03-13',
  '2026-03-13'
) ON CONFLICT (id) DO NOTHING;

-- Pattern: config-setup-inversion
INSERT INTO patterns (id, name, status, confidence, protocol_md, trigger_keywords, trigger_error_signatures, times_used, times_correct, false_positives, false_positive_log, sprint_validated, created_at)
VALUES (
  'config-setup-inversion',
  'Config Setup Step Inverted Boolean',
  'active',
  'HIGH',
  E'# Pattern: Config Setup Step Inversion\n\n**ID**: config-setup-inversion\n\n---\n\n## TRIGGER\n\nActivate this pattern when ALL of the following are true:\n\n- Test has setup steps that call a config/platform-settings API (Zeus, admin config, feature flags)\n- The test fails at a functional step that depends on a feature being ON\n- The failure is a timeout or element not found — not an assertion mismatch on a value\n\n**Common step patterns:**\n- `API - Update ''Auto Moderate Settings'' for ''(.+)'' as ''Enabled''`\n- `API - Update ''Auto Moderate Settings'' for ''(.+)'' as ''Disabled''`\n\n---\n\n## PROTOCOL\n\n### Step 1 — Extract config API calls from the Serenity JSON (failing run)\n\nThe Serenity JSON records REST interactions including request bodies.\n\n```python\nimport json, sys\nwith open(\"<serenity_json_file>\") as f:\n    data = json.load(f)\ndef find_rest(steps, depth=0):\n    for s in steps:\n        for r in s.get(''restQuery'', []):\n            print(f\"[REST] {r.get(''method'')} {r.get(''path'')} -> body: {r.get(''content'')}\")\n        for e in s.get(''reportData'', []):\n            print(f\"[DATA] {e.get(''title'')} -> {e.get(''contents'')}\")\n        find_rest(s.get(''children'', []), depth+1)\nfind_rest(data.get(''testSteps'', []))\n```\n\nLook for PUT/POST to config/Zeus endpoints. Record config key and value sent.\n\n**If Serenity did not capture the REST body** → ask user for console log.\n\n### Step 2 — Extract config API calls from passing run\n\nRepeat Step 1 against a known passing run.\n\n**Key question**: Does the failing run send the opposite boolean?\n\n| Step Name says | Passing sends | Failing sends | Verdict |\n|---|---|---|---|\n| as ''Enabled'' | true | false | INVERSION BUG |\n| as ''Disabled'' | false | true | INVERSION BUG |\n| as ''Enabled'' | true | true | Not this pattern |\n\n### Step 3 — Locate the step definition\n\n```bash\ngrep -r \"as ''Enabled''\\|as ''Disabled''\\|updateAutoModerate\" $QA_REPO/src/main/java --include=\"*.java\" -l\n```\n\n### Step 4 — Git log on the step definition file\n\n```bash\ngit -C $QA_REPO log --oneline --since=\"14 days ago\" -- <step_definition_file>\n```\n\n### Step 5 — Check blast radius\n\n```bash\ngrep -r \"as ''Enabled''\\|as ''Disabled''\" $QA_REPO/src/test/resources/features --include=\"*.feature\" -l\n```\n\n---\n\n## TERMINATION CONDITIONS\n\n| Outcome | Classification | Confidence |\n|---|---|---|\n| Boolean inverted + sprint-window commit found | QA Automation | HIGH |\n| Boolean inverted + no recent commit | QA Automation | MEDIUM |\n| Values match between passing/failing | Not this pattern | N/A |',
  ARRAY['Auto Moderate Settings', 'PROBATIONAL_APPROVAL', 'platform-config', 'zeus config', 'as ''Enabled''', 'as ''Disabled'''],
  ARRAY['updateAutoModerateSettingsAs', 'updateAutoModerate', 'platform-config/504'],
  1, 1, 0,
  '[]'::jsonb,
  '2026-03-13',
  '2026-03-13'
) ON CONFLICT (id) DO NOTHING;

-- Pattern: admin-session-cookie-survival
INSERT INTO patterns (id, name, status, confidence, protocol_md, trigger_keywords, trigger_error_signatures, times_used, times_correct, false_positives, false_positive_log, sprint_validated, created_at)
VALUES (
  'admin-session-cookie-survival',
  'Admin Session Switch Cookie Survival',
  'active',
  'HIGH',
  E'# Pattern: Admin Session Switch Cookie Survival\n\n**ID**: admin-session-cookie-survival\n\n---\n\n## TRIGGER\n\nActivate this pattern when ALL of the following are true:\n\n- Test switches from member domain → admin → back to member domain mid-scenario\n- Failure occurs on the member page after the admin session block\n- Error is element not found, element not enabled, or modal not rendered — on a feature that is cookie-gated\n- Recent QA commit touches AdminLoginSteps.java, LoginSteps.java, goToLoginPageWithUrl(), or deleteAllCookies() ordering\n\n**Do NOT activate** if the test never visits admin, or if failure occurs before the admin session block.\n\n---\n\n## PROTOCOL\n\n### Step 1 — Confirm the test flow pattern\n\n```bash\ngrep -n \"Admin user logs into\\|Admin user searches\\|Directly navigate to ''Member''\\|Complete my profile\\|skipPcrAfterLogin\" $QA_REPO/src/test/resources/features/**/<test_file>.feature\n```\n\nConfirm: login step sets cookies → admin block follows → test navigates back to member → failing step depends on cookie-gated feature.\n\n### Step 2 — Check deleteAllCookies() ordering in AdminLoginSteps\n\n```bash\ngrep -n -A10 \"goToLoginPageWithUrl\\|deleteAllCookies\" $QA_REPO/src/main/java/incube8/seeking/steps/admin/general/AdminLoginSteps.java\n```\n\n**Safe ordering:**\n```java\nadminLoginPage.getDriver().manage().deleteAllCookies(); // on member domain\nadminLoginPage.open(\"admin-login\", ...);\n```\n\n**Broken ordering:**\n```java\nadminLoginPage.open(\"admin-login\", ...);               // navigates away first\nadminLoginPage.getDriver().manage().deleteAllCookies(); // now on admin domain\n```\n\n### Step 3 — Find the sprint trigger\n\n```bash\ngit -C $QA_REPO log --oneline --since=\"14 days ago\" -- src/main/java/incube8/seeking/steps/admin/general/AdminLoginSteps.java\ngit -C $QA_REPO log --oneline --since=\"14 days ago\" -S \"deleteAllCookies\\|goToLoginPageWithUrl\" -- src/main/java/incube8/seeking/steps/admin/general/AdminLoginSteps.java\n```\n\n### Step 4 — Identify which cookie survived\n\n```bash\ngrep -n \"skipPcrAfterLogin\\|addCookie\\|pcrHide\\|membership-modal\" $QA_REPO/src/main/java/incube8/seeking/steps/profile/edit/ProfileWallSteps.java $QA_REPO/src/main/java/incube8/seeking/steps/general/wp_public/LoginSteps.java\n```\n\n---\n\n## TERMINATION CONDITIONS\n\n| Outcome | Classification | Confidence |\n|---------|---------------|------------|\n| deleteAllCookies() ordering changed, cookie survives | QA Automation | HIGH |\n| Ordering unchanged but Serenity upgrade changed WebDriver init | QA Automation | MEDIUM |\n| Cookie survival confirmed but no recent commit | Flaky/Inconclusive | LOW |',
  ARRAY['Admin user logs into the application', 'Complete my profile', 'Profile Wall', 'deleteAllCookies', 'skipPcrAfterLogin', 'goToLoginPageWithUrl'],
  ARRAY['Expected enabled element was not enabled', 'elementToBeCurrentlyVisible', 'ProfileWallDefinitions'],
  1, 1, 0,
  '[]'::jsonb,
  '2026-03-14',
  '2026-03-14'
) ON CONFLICT (id) DO NOTHING;

