-- Feedback entries (flattened from reports/feedback-log.json)
INSERT INTO feedback_entries (run_id, test_name, system_classification, actual_classification, classification_correct, pattern_used, pattern_match_correct, key_investigative_step, new_pattern_candidate, new_pattern_trigger, new_pattern_protocol, notes) VALUES
  ('2026-03-13T02:57:25Z', 'Validate ID Verification Underage Improvements - Underage Registration', 'QA Automation', 'QA Automation', 'yes', NULL, NULL, 'Computing exact idvBirthdate from AdminPASApiSteps.java formula and comparing against account_created', TRUE, 'Date-sensitive arithmetic in QA step definitions produces boundary failures on specific calendar dates when leap-year spans are involved', '1. Extract the birthdate/date formula from the step definition. 2. Compute the exact date for the run date. 3. Check if result lands on an exact boundary (18 years, 21 years etc). 4. Fix: anchor to account_created not today, or add safety buffer days.', 'Root cause: idvBirthdate = today.minusYears(19).plusDays(356) lands on 2008-03-01 when today=2026-03-11'),
  ('2026-03-13T10:32:45Z', 'Validation Not Met - Username criteria for Profile Auto-Moderation', 'Inconclusive', 'Inconclusive — shared QA Automation + BE interaction', 'partial', NULL, NULL, 'Cross-referencing conditional rendering in approvals.blade.php with dispatchSync call in UpdateProfileEventRequest.php', FALSE, NULL, NULL, 'Root cause: ProcessDragynTextAssessment::dispatchSync omits Dragyn::getRequestData() — qa_reason never reaches the job'),
  ('2026-03-13T062028Z', 'Validate Re-moderation for Eye Verification', 'QA Automation', 'QA Automation', 'yes', 'config-setup-inversion', TRUE, 'Comparing passing vs failing Jenkins console logs — PUT body for Zeus config 504 showed inverted values', TRUE, 'A setup step named as Enabled or as Disabled sends the wrong boolean value', '1. Find the Zeus config PUT calls in the failing console log. 2. Compare the value sent against a passing run. 3. If inverted, check git log on AdminApiConfigurationDefinitions.java.', 'Commit message Updated for testing strongly suggests temporary debug change never reverted'),
  ('2026-03-13T12:37:00Z', 'Validation of Dragyn Photo Moderation with Attractive and Generous Members', 'QA Automation', 'External Service — Dragyn Misclassification', 'no', 'dragyn-false-positive', TRUE, 'Serenity recordReportData captured Dragyn reason as -> Minor in photo', FALSE, NULL, NULL, 'Two wrong classifications before correct answer. Key lesson: always read Serenity recordReportData for actual Dragyn reason'),
  ('2026-03-13T113341Z', 'Validate Email Change Restriction for New Accounts and View in Admin', 'QA Automation', 'QA Automation', 'yes', 'admin-session-cookie-survival', TRUE, 'Pattern match at Stage 0 — exact Known Instance 1 hit. No additional investigation required.', FALSE, NULL, NULL, 'Second consecutive failure across two branches. Fix not yet applied.'),
  ('2026-03-13T140000Z', 'Validate Email Change Restriction for New Accounts and View in Admin', 'FE Code', 'QA Automation', 'no', 'admin-session-cookie-survival', TRUE, 'QA team identified that goToLoginPageWithUrl() reorder in b30c74a029 moved deleteAllCookies()', FALSE, NULL, NULL, 'System initially classified as FE Code. Key lesson: always check recent QA commits to shared helpers BEFORE moving to FE/BE investigation.'),
  ('2026-03-13T03-25-05Z', 'Validate Nickname field attempts on Edit Profile And PAS Queue', 'FE Code', 'QA Automation', 'no', 'admin-session-cookie-survival', TRUE, 'Recognising ProfileWallDefinitions failure post-admin-block is the same admin-session-cookie-survival mechanism', FALSE, NULL, NULL, 'Original investigation misled by 227a0ca07c touching AfterLoginPCR.tsx. Actual sprint trigger: b30c74a029.');
